149→        onFollowingPress={onFollowingPress}
150→      />
151→      <ProfileTabBar activeTab={activeTab} onTabChange={setActiveTab} />
152→      <View style={styles.tabSpacer} />
153→    </View>
154→  );
155→
156→  return (
157→    <SafeAreaView
158→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
159→      edges={['top']}>
160→      {backdropElement}
161→
162→      {activeTab === 'writings' ? (
163→        <ProfileWritingsTab
164→          userId={user?.id ?? ''}
165→          headerComponent={headerComponent}
