 37→const toCount = (value: unknown): number | null => {
 38→  const parsed = Number(value);
 39→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 40→};
 41→
 42→const resolveCount = (
 43→  aggregate: Array<{count?: number}> | undefined,
 44→  fallback?: number,
 45→): number => {
 46→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 47→};
 48→
 49→const extractBannerImage = (content: string | null | undefined): string | null => {
 50→  if (!content) return null;
 51→  try {
 52→    const parsed = JSON.parse(content);
 53→    const findImage = (node: any): string | null => {
 54→      if (node.type === 'image' && node.src) return node.src;
 55→      if (node.children) {
 56→        for (const child of node.children) {
 57→          const found = findImage(child);
 58→          if (found) return found;
 59→        }
 60→      }
 61→      return null;
 62→    };
 63→    return findImage(parsed.root ?? parsed);
 64→  } catch {
 65→    return null;
 66→  }
 67→};
