23→    queryFn: () => mobileApi.searchJournals(normalizedQuery, 10),
24→  });
25→
26→  const users: UserPreview[] = usersQuery.data?.data ?? [];
27→  const journals: JournalItem[] = journalsQuery.data?.data ?? [];
28→
29→  return {
30→    query,
31→    setQuery,
32→    activeTab,
33→    setActiveTab,
34→    isSearching,
35→    normalizedQuery,
36→    users,
37→    journals,
38→  };
