69→export const calculateReadingTime = (text: string): string => {
70→  const wordPerMin = 150;
71→  const words = text.trim().split(/\s+/).length;
72→  const readingTime = Math.ceil(words / wordPerMin);
73→  if (readingTime > 1) {
74→    return `${readingTime} mins read`;
75→  }
76→  return `${readingTime} min read`;
77→};
78→
79→export const getNextCursor = (
80→  page: CursorPage<JournalItem>,
81→  pageSize: number,
82→): string | undefined => {
83→  if (page.nextCursor) return page.nextCursor;
84→  if (page.hasMore && page.data.length > 0)
85→    return page.data[page.data.length - 1]?.created_at ?? undefined;
86→  if (page.data.length >= pageSize)
87→    return page.data[page.data.length - 1]?.created_at ?? undefined;
88→  return undefined;
89→};
